export function getCategory(slug) { return categories.find(c => c.slug === slug) }
export function getListingsByCategory(catSlug) { return listings.filter(l => l.category === catSlug) }
export function getListing(slug) { return listings.find(l => l.slug === slug) }
export function getAllListings() { return listings }
export function getFeaturedListings() { return listings.filter(l => l.featured) }
export function getCategoriesWithCounts() { return categories.map(c => ({ ...c, count: listings.filter(l => l.category === c.slug).length })) }
